from math import gcd
from oeis_sequences.OEISsequences import bisection
def A112757(n):
    def f(x):
        c = n+x
        i, i5 = 0, 1
        while i5<=x:
            j, j3 = 0, 1
            y = x//i5
            z = y
            while j3 <= y:
                c -= z.bit_length()
                j += 1
                j3 *= 3
                z //= 3
            i += 1
            i5 *= 5
        return c
